// src/store/slices/cartSlice.js

import { createSlice } from '@reduxjs/toolkit';

const cartSlice = createSlice({
  name: 'cart',
  initialState: {
    list: JSON.parse(localStorage.getItem('cart')) || [],
  },
  reducers: {
    addToCart: (state, action) => {
      // payload: { id, title, price, ... , quantity }
      const item = action.payload;
      const existingItem = state.list.find(p => p.id === item.id);

      // 🔑 Используем переданное количество. Если оно почему-то отсутствует, используем 1.
      const quantityToAdd = item.quantity || 1; 

      if (existingItem) {
        // Если товар уже есть, ДОБАВЛЯЕМ переданное количество к существующему.
        existingItem.quantity += quantityToAdd; 
      } else {
        // Если товар новый, добавляем его с переданным количеством.
        state.list.push({ ...item, quantity: quantityToAdd }); 
      }
      localStorage.setItem('cart', JSON.stringify(state.list));
    },

    // 💡 Дополнительные функции для управления корзиной
    // (Эти функции предполагают, что управление количеством происходит по +1/-1)
    incrementItem: (state, action) => {
      const id = action.payload;
      const item = state.list.find(p => p.id === id);
      if (item) {
        item.quantity += 1;
        localStorage.setItem('cart', JSON.stringify(state.list));
      }
    },

    decrementItem: (state, action) => {
      const id = action.payload;
      const itemIndex = state.list.findIndex(p => p.id === id);

      if (itemIndex !== -1) {
        const item = state.list[itemIndex];
        item.quantity -= 1;

        if (item.quantity <= 0) {
          // Удаляем товар, если количество достигло 0
          state.list.splice(itemIndex, 1);
        }
        localStorage.setItem('cart', JSON.stringify(state.list));
      }
    },

    removeFromCart: (state, action) => {
      const id = action.payload;
      state.list = state.list.filter(item => item.id !== id);
      localStorage.setItem('cart', JSON.stringify(state.list));
    },

    clearCart: (state) => {
      state.list = [];
      localStorage.removeItem('cart');
    }
  },
});

export const { 
    addToCart, 
    incrementItem, 
    decrementItem, 
    removeFromCart,
    clearCart
} = cartSlice.actions;

export default cartSlice.reducer;
